import numpy as np
import json
import time
from collections import defaultdict, deque
from typing import Dict, List, Tuple, Optional, Any
from dataclasses import dataclass, asdict
import threading
import queue

@dataclass
class ConversationState:
    topic: str
    complexity: float
    user_intent: str
    model_used: str
    response_quality: float
    timestamp: float

class MarkovContextOrchestrator:
    """
    Markov-chain based context orchestration for predictive model routing
    Implements MVCO methodology for local consumer hardware
    """

    def __init__(self, config_manager=None, max_history: int = 10000):
        self.config = config_manager
        self.max_history = max_history

        # State tracking
        self.conversation_states = deque(maxlen=max_history)
        self.transition_matrix = defaultdict(lambda: defaultdict(float))
        self.state_counts = defaultdict(int)

        # Model performance tracking
        self.model_performance = defaultdict(lambda: {'success_rate': 0.5, 'avg_response_time': 5.0, 'quality_score': 0.7})

        # Prediction cache for performance
        self.prediction_cache = {}
        self.cache_ttl = 300  # 5 minutes

        # Background learning thread
        self.learning_queue = queue.Queue()
        self.learning_active = True
        self.learning_thread = threading.Thread(target=self._background_learner, daemon=True)
        self.learning_thread.start()

    def add_interaction(self, prompt: str, response: str, model_used: str,
                        response_time: float, quality_score: float = None):
        """Record an interaction for Markov chain learning"""
        current_state = ConversationState(
            topic=self._extract_topic(prompt),
            complexity=self._assess_complexity(prompt),
            user_intent=self._classify_intent(prompt),
            model_used=model_used,
            response_quality=quality_score or self._estimate_quality(response),
            timestamp=time.time()
        )

        # Update transition matrix if we have a previous state
        if self.conversation_states:
            prev_state = self.conversation_states[-1]
            self._update_transitions(prev_state, current_state)

        self.conversation_states.append(current_state)

        # Update model performance
        self.model_performance[model_used]['avg_response_time'] = (
            self.model_performance[model_used]['avg_response_time'] * 0.9 + response_time * 0.1
        )
        if quality_score:
            self.model_performance[model_used]['quality_score'] = (
                self.model_performance[model_used]['quality_score'] * 0.9 + quality_score * 0.1
            )

        # Queue for background learning
        self.learning_queue.put(('interaction', current_state))

    def predict_next_state(self, current_prompt: str) -> Dict[str, Any]:
        """Predict optimal model and parameters for next interaction"""
        # Create cache key
        cache_key = hash(current_prompt[:200])
        current_time = time.time()

        if cache_key in self.prediction_cache:
            cached_result, cached_time = self.prediction_cache[cache_key]
            if current_time - cached_time < self.cache_ttl:
                return cached_result

        # Analyze current prompt
        current_topic = self._extract_topic(current_prompt)
        current_complexity = self._assess_complexity(current_prompt)
        current_intent = self._classify_intent(current_prompt)

        # Find similar historical states
        similar_states = self._find_similar_states(current_topic, current_complexity, current_intent)

        # Predict best model based on historical performance
        model_scores = {}
        for model, perf in self.model_performance.items():
            # Base score from historical performance
            base_score = perf['quality_score'] * 0.6 + (1 / (1 + perf['avg_response_time'])) * 0.4

            # Adjust based on similar states
            similar_score = np.mean([s.response_quality for s in similar_states
                                     if s.model_used == model]) if similar_states else 0.5

            model_scores[model] = base_score * 0.7 + similar_score * 0.3

        # Get best model
        best_model = max(model_scores.items(), key=lambda x: x[1])[0] if model_scores else 'gemma2:2b'

        # Predict optimal parameters
        predicted_response_time = self.model_performance[best_model]['avg_response_time']

        prediction = {
            'recommended_model': best_model,
            'confidence': min(0.95, len(similar_states) / 10.0),
            'predicted_response_time': predicted_response_time,
            'predicted_quality': model_scores.get(best_model, 0.7),
            'context_limit': self._recommend_context_limit(current_complexity),
            'similar_interactions': len(similar_states)
        }

        # Cache the result
        self.prediction_cache[cache_key] = (prediction, current_time)

        return prediction

    def _extract_topic(self, text: str) -> str:
        """Extract main topic from text using simple keyword clustering"""
        # Simple topic extraction - could be enhanced with NLP
        keywords = ['code', 'programming', 'math', 'science', 'creative', 'analysis',
                    'question', 'help', 'explain', 'generate', 'write', 'debug']
        text_lower = text.lower()
        for keyword in keywords:
            if keyword in text_lower:
                return keyword
        return 'general'

    def _assess_complexity(self, text: str) -> float:
        """Assess text complexity (0-1 scale)"""
        factors = []

        # Length factor
        factors.append(min(1.0, len(text) / 1000))

        # Complex words
        complex_words = ['analyze', 'synthesize', 'evaluate', 'implement', 'optimize']
        factors.append(min(1.0, sum(1 for word in complex_words if word in text.lower()) / 3))

        # Question complexity
        factors.append(min(1.0, text.count('?') / 3))

        return np.mean(factors)

    def _classify_intent(self, text: str) -> str:
        """Classify user intent"""
        intents = {
            'question': ['what', 'how', 'why', 'when', 'where', '?'],
            'creation': ['create', 'make', 'build', 'generate', 'write'],
            'analysis': ['analyze', 'compare', 'evaluate', 'assess'],
            'help': ['help', 'assist', 'support', 'guide'],
            'explanation': ['explain', 'describe', 'tell me', 'show me']
        }
        text_lower = text.lower()
        for intent, keywords in intents.items():
            if any(keyword in text_lower for keyword in keywords):
                return intent
        return 'general'

    def _update_transitions(self, prev_state: ConversationState, current_state: ConversationState):
        """Update Markov transition matrix"""
        prev_key = (prev_state.topic, prev_state.user_intent, prev_state.model_used)
        current_key = (current_state.topic, current_state.user_intent)
        self.transition_matrix[prev_key][current_key] += 1
        self.state_counts[prev_key] += 1

    def _find_similar_states(self, topic: str, complexity: float, intent: str,
                             n_similar: int = 10) -> List[ConversationState]:
        """Find similar conversation states"""
        similar_states = []
        for state in self.conversation_states:
            similarity = 0
            if state.topic == topic:
                similarity += 0.4
            if abs(state.complexity - complexity) < 0.2:
                similarity += 0.3
            if state.user_intent == intent:
                similarity += 0.3

            if similarity > 0.3:  # Threshold for similarity
                similar_states.append(state)

        # Return most recent similar states
        return sorted(similar_states, key=lambda x: x.timestamp, reverse=True)[:n_similar]

    def _recommend_context_limit(self, complexity: float) -> int:
        """Recommend context limit based on complexity and hardware"""
        base_limit = 4096
        if complexity > 0.7:
            return min(8192, int(base_limit * 2))  # High complexity needs more context
        elif complexity < 0.3:
            return max(2048, int(base_limit // 2))  # Low complexity can use less context
        return base_limit

    def _estimate_quality(self, response: str) -> float:
        """Estimate response quality using simple heuristics"""
        if not response or len(response) < 20:
            return 0.1

        quality_score = 0.5  # Base score

        # Length (reasonable responses should be substantial but not excessive)
        length_score = min(1.0, len(response) / 500)
        quality_score += length_score * 0.2

        # Structure indicators
        if '\n' in response:  # Structured response
            quality_score += 0.1
        if any(marker in response for marker in ['1.', '2.', '-', '*']):  # Lists
            quality_score += 0.1
        if len(response.split('.')) > 2:  # Multiple sentences
            quality_score += 0.1

        return min(1.0, quality_score)

    def _background_learner(self):
        """Background thread for continuous learning"""
        while self.learning_active:
            try:
                task = self.learning_queue.get(timeout=1)
                if task[0] == 'interaction':
                    # Perform background learning tasks
                    self._optimize_transitions()
                    self._cleanup_old_data()
            except queue.Empty:
                continue
            except Exception as e:
                print(f"Background learning error: {e}")

    def _optimize_transitions(self):
        """Optimize transition matrix by normalizing probabilities"""
        for prev_state, transitions in self.transition_matrix.items():
            total = sum(transitions.values())
            if total > 0:
                for next_state in transitions:
                    transitions[next_state] /= total

    def _cleanup_old_data(self):
        """Clean up old cache entries"""
        current_time = time.time()
        expired_keys = [key for key, (_, timestamp) in self.prediction_cache.items()
                        if current_time - timestamp > self.cache_ttl]

        for key in expired_keys:
            del self.prediction_cache[key]

    def get_statistics(self) -> Dict[str, Any]:
        """Get learning statistics"""
        return {
            'total_interactions': len(self.conversation_states),
            'unique_states': len(self.state_counts),
            'models_tracked': list(self.model_performance.keys()),
            'cache_size': len(self.prediction_cache),
            'avg_prediction_confidence': np.mean([
                pred[0]['confidence'] for pred in self.prediction_cache.values()
            ]) if self.prediction_cache else 0.0
        }

    def bootstrap_with_models(self, models: List[str]) -> None:
        """Optional: seed internal model statistics to avoid cold start."""
        if not models:
            return
        for model in models:
            if model not in self.model_performance:
                # Initialize with baseline performance metrics
                self.model_performance[model] = {
                    'success_rate': 0.5,
                    'avg_response_time': 5.0,
                    'quality_score': 0.7
                }

    def shutdown(self):
        """Shutdown the orchestrator"""
        self.learning_active = False
        if self.learning_thread.is_alive():
            self.learning_thread.join()

# Alias for compatibility
MVCO = MarkovContextOrchestrator